class Solution {
    public int numberOfArrays(String s, int k) {
        int mod = (int) 1e9 + 7;
        int n = s.length();
        long[] dp = new long[n + 1];
        dp[n] = 1;

        for (int i = n - 1; i >= 0; i--) {
            if (s.charAt(i) == '0') continue;
            for (int j = i; j < n; j++) {
                long num = Long.parseLong(s.substring(i, j + 1));
                if (num > k) break;
                dp[i] = (dp[i] + dp[j + 1]) % mod;
            }
        }
        return (int) dp[0];
    }
}
